mapper.select:
/* AdminPopupMapper.selectPopupTotalCount */
SELECT
	COUNT(1)
FROM
	TB_MAIN_POPUP


		AND POPUP_TY = #{popupTy}


		AND POPUP_SE = #{popupSe}


		AND SITE_CODE = #{siteCode}


		AND USE_YN = #{useYn}


		AND POPUP_SJ LIKE CONCAT('%', #{popupSj} ,'%')

/* AdminPopupMapper.selectPopupTotalCount */ SELECT POPUP_SEQ AS popupSeq ,POPUP_SJ AS popupSj ,BGNDE_DE AS bgndeDe ,END_DE AS endDe ,POPUP_ORDR AS popupOrdr ,POPUP_TY AS popupTy ,POPUP_SE AS popupSe ,SITE_CODE AS siteCode ,USE_YN AS useYn ,REG_ID AS regId ,DATE_FORMAT(REG_DT, '%Y-%m-%d %H:%i:%s') AS regDt ,UPD_ID AS updId ,DATE_FORMAT(UPD_DT, '%Y-%m-%d %H:%i:%s') AS updDt FROM TB_MAIN_POPUP
AND POPUP_TY = #{popupTy}
AND POPUP_SE = #{popupSe}
AND SITE_CODE = #{siteCode}
AND USE_YN = #{useYn}
AND POPUP_SJ LIKE CONCAT('%', #{popupSj} ,'%')
ORDER BY REG_DT DESC LIMIT #{offset}, #{pageSize}

mapper.insert:
/* AdminPopupMapper.insertPopup */
INSERT INTO TB_MAIN_POPUP (
	 POPUP_SJ
	,POPUP_URL
	,ATCHFILENO
	,POPUP_WIDTH_LC
	,POPUP_HEIGHT_LC
	,POPUP_WIDTH
	,POPUP_HEIGHT
	,BGNDE_DE
	,END_DE
	,POPUP_ORDR
	,POPUP_CN
	,POPUP_TY
	,POPUP_SE
	,SITE_CODE
	,USE_YN
	,REG_ID
	,REG_DT
	,UPD_ID
	,UPD_DT
) VALUES (
	 #{popupSj}
	,#{popupUrl}
	,#{atchfileno}
	,#{popupWidthLc}
	,#{popupHeightLc}
	,#{popupWidth}
	,#{popupHeight}
	,#{bgndeDe}
	,#{endDe}
	,#{popupOrdr}
	,#{popupCn}
	,#{popupTy}
	,#{popupSe}
	,#{siteCode}
	,#{useYn}
	,#{userId}
	,now()
	,#{userId}
	,now()
)

mapper.update:
/* AdminPopupMapper.updatePopup */
UPDATE TB_MAIN_POPUP
SET
	 POPUP_SJ			= #{popupSj}
	,POPUP_URL			= #{popupUrl}
	,ATCHFILENO			= #{atchfileno}
	,POPUP_WIDTH_LC		= #{popupWidthLc}
	,POPUP_HEIGHT_LC	= #{popupHeightLc}
	,POPUP_WIDTH		= #{popupWidth}
	,POPUP_HEIGHT		= #{popupHeight}
	,BGNDE_DE			= #{bgndeDe}
	,END_DE				= #{endDe}
	,POPUP_ORDR			= #{popupOrdr}
	,POPUP_CN			= #{popupCn}
	,POPUP_TY			= #{popupTy}
	,POPUP_SE			= #{popupSe}
	,SITE_CODE			= #{siteCode}
	,USE_YN				= #{useYn}
	,UPD_ID				= #{userId}
	,UPD_DT				= now()
WHERE
	POPUP_SEQ = #{popupSeq}

mapper.delete:
/* AdminPopupMapper.deletePopup */
DELETE FROM TB_MAIN_POPUP
WHERE
	POPUP_SEQ = #{popupSeq}
